using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Hosting;
using Microsoft.Extensions.Logging;

var builder = Host.CreateApplicationBuilder(args);

// CRITICAL: stdio transport uses stdout for JSON-RPC — all logs must go to stderr.
builder.Logging.AddConsole(options =>
    options.LogToStandardErrorThreshold = LogLevel.Trace);

builder.Services.AddHttpClient<ApiMcpServer.ApiTools>(client =>
{
    // Point this at the real API base address.
    client.BaseAddress = new Uri("https://jsonplaceholder.typicode.com");
});

builder.Services.AddMcpServer(options =>
{
    options.ServerInfo = new() { Name = "ApiMcpServer", Version = "1.0.0" };
    options.ServerInstructions = "Use these tools to manage users via the REST API.";
})
.WithStdioServerTransport()
.WithToolsFromAssembly();

await builder.Build().RunAsync();

